   151→			continue
   152→		}
   153→
   154→		versionedAttr, err := v.VersionedAttribute(invocation.Kind)
   155→		if err != nil {
   156→			return apierrors.NewInternalError(err)
   157→		}
   158→
   159→		t := time.Now()
   160→		round := 0
   161→		if reinvokeCtx.IsReinvoke() {
   162→			round = 1
   163→		}
   164→
