   167→		ignoreClientCallFailures := hook.FailurePolicy != nil && *hook.FailurePolicy == admissionregistrationv1.Ignore
   168→		rejected := false
   169→		if err != nil {
   170→			switch err := err.(type) {
   171→			case *webhookutil.ErrCallingWebhook:
   172→				if !ignoreClientCallFailures {
   173→					rejected = true
